import { useState, useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';
import { useToast } from '../components/ui/Toast';
import { useTracking } from './useTracking';
import DOMPurify from 'dompurify';

interface GenerationResult {
  resumeHtml?: string;
  coverLetterHtml?: string;
  rawText: string;
  metadata?: Record<string, unknown>;
}

interface GenerationOptions {
  systemPrompt: string;
  userPrompt: string;
  model?: string;
  /** Timeout in ms (default 90000) */
  timeout?: number;
  /** Optional cache key — if provided, edge function caches the response */
  cacheKey?: string;
  /** Cache TTL in seconds (default 86400 = 24h) */
  cacheTtlSeconds?: number;
}

function extractCodeBlocks(text: string): string[] {
  const blocks: string[] = [];
  const regex = /```(?:\w+)?\s*\n([\s\S]*?)```/g;
  let match;
  while ((match = regex.exec(text)) !== null) {
    blocks.push(match[1].trim());
  }
  return blocks;
}

function sanitizeHtml(html: string): string {
  if (typeof DOMPurify !== 'undefined' && DOMPurify.sanitize) {
    return DOMPurify.sanitize(html);
  }
  // Fallback: strip dangerous tags
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<iframe[\s\S]*?<\/iframe>/gi, '')
    .replace(/on\w+="[^"]*"/gi, '')
    .replace(/javascript:/gi, '');
}

function withTimeout<T>(promise: Promise<T>, ms: number): Promise<T> {
  return Promise.race([
    promise,
    new Promise<never>((_, reject) =>
      setTimeout(() => reject(new Error(`Request timed out after ${ms}ms`)), ms)
    ),
  ]);
}

export function useGeminiGeneration() {
  const { invokeEdgeFunction, user } = useAuth();
  const { showToast } = useToast();
  const { trackEvent } = useTracking();
  const [isGenerating, setIsGenerating] = useState(false);
  const [progress, setProgress] = useState('');

  const generate = useCallback(async (options: GenerationOptions): Promise<GenerationResult | null> => {
    const { systemPrompt, userPrompt, model = 'gemini-3-flash-preview', timeout = 90000, cacheKey, cacheTtlSeconds } = options;

    if (!user) {
      showToast('Please sign in to generate content.', true);
      return null;
    }

    setIsGenerating(true);
    setProgress('Generating...');

    try {
      const payload: Record<string, unknown> = {
        model,
        systemInstruction: { parts: [{ text: systemPrompt }] },
        contents: [{ role: 'user', parts: [{ text: userPrompt }] }],
        generationConfig: { temperature: 0.7 },
      };
      if (cacheKey) {
        payload.cacheKey = cacheKey;
        if (cacheTtlSeconds) payload.cacheTtlSeconds = cacheTtlSeconds;
      }

      const { data, error } = await withTimeout(
        invokeEdgeFunction('gemini-proxy', payload),
        timeout
      );

      if (error) {
        showToast(error.message, true);
        return null;
      }

      // Navigate Gemini API response format: candidates[0].content.parts[0].text
      const response = data as Record<string, unknown>;
      const candidates = (response?.candidates as Array<{ content?: { parts?: Array<{ text?: string }> } }>) ?? [];
      const rawText = candidates[0]?.content?.parts?.[0]?.text || '';

      if (!rawText) {
        showToast('Empty response from AI. Please try again.', true);
        return null;
      }

      const blocks = extractCodeBlocks(rawText);
      let resumeHtml: string | undefined;
      let metadata: Record<string, unknown> | undefined;

      // First block is usually HTML, second is JSON metadata
      if (blocks.length >= 1) {
        resumeHtml = sanitizeHtml(blocks[0]);
      }
      if (blocks.length >= 2) {
        try {
          metadata = JSON.parse(blocks[1]);
        } catch {
          // Not valid JSON, treat as additional content
        }
      }

      // Track successful generation
      const matchScore = metadata?.matchScore;
      trackEvent('ai:generate', {
        model,
        has_html: !!resumeHtml,
        has_metadata: !!metadata,
        match_score: matchScore ?? null,
        prompt_length: userPrompt.length,
      });

      return {
        resumeHtml,
        rawText: sanitizeHtml(rawText),
        metadata,
      };
    } catch (err) {
      const msg = err instanceof Error ? err.message : 'Generation failed';
      showToast(msg, true);
      return null;
    } finally {
      setIsGenerating(false);
      setProgress('');
    }
  }, [invokeEdgeFunction, user, showToast]);

  return { generate, isGenerating, progress };
}
