import { useCallback } from 'react';
import { useAuth } from '../context/SupabaseContext';

/**
 * Lightweight event tracking hook.
 * Fires analytics events to Supabase analytics_events table.
 *
 * Usage:
 *   const { trackEvent } = useTracking();
 *   trackEvent('tool:click', { slug: 'cover-letter' });
 *   trackEvent('resume:generate', { match_score: 85, latency_ms: 3200 });
 */
export function useTracking() {
  const { supabase, user } = useAuth();

  const trackEvent = useCallback(
    async (eventType: string, metadata?: Record<string, unknown>) => {
      try {
        await supabase.from('analytics_events').insert({
          user_id: user?.id ?? null,
          event_type: eventType,
          page_path: window.location.pathname,
          metadata: metadata ?? {},
        });
      } catch {
        // Tracking should never break the app — silently fail
      }
    },
    [supabase, user]
  );

  return { trackEvent };
}
